mapper.select:
SELECT appointment_id, appointment_no, elder_id, elder_name, elder_phone, elder_address,
       district_code, service_type_code, service_type_name, appointment_date, appointment_time,
       service_hours, status, status_name, dispatch_time, receive_time,
       staff_id, staff_name, staff_phone, provider_id, provider_name,
       remark, cancel_reason, registration_fee, service_fee, subsidy_amount, self_pay_amount,
       order_id, create_time, update_time
FROM appointment
WHERE validity = 'VALID'

    AND appointment_no LIKE CONCAT('%', #{query.appointmentNo}, '%')


    AND elder_name LIKE CONCAT('%', #{query.elderName}, '%')


    AND elder_phone = #{query.elderPhone}


    AND service_type = #{query.serviceType}


    AND service_type_code = #{query.serviceTypeCode}


    AND status = #{query.status}


    AND elder_area_id = #{query.areaId}


    AND provider_id = #{query.providerId}


    AND staff_id = #{query.staffId}


    AND appointment_time >= #{query.startDate}


    AND appointment_time <= #{query.endDate}

ORDER BY create_time DESC
